Greedy insertion with cost-aware selection and fallback to new assign for uninsertable orders, evaluating all candidate assigns via trial-and-rollback while preserving state.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		bestAssignIdx := -1
		bestCostDelta := 0.0
		fallbackAssignIdx := -1

		for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]

			oldCost := assign.Cost
			success := assign.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if !success {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			costDelta := newCost - oldCost

			assign.RemoveShip(total_ship + shipIdx)
			assign.GenRoute()

			if bestAssignIdx == -1 || costDelta < bestCostDelta {
				bestAssignIdx = assignIdx
				bestCostDelta = costDelta
			}
		}

		if bestAssignIdx != -1 {
			targetAssign := &dispatch.Assigns[bestAssignIdx]
			targetAssign.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			targetAssign.GenRoute()
		} else {
			fallbackAssignIdx = dispatch.AssignsLen
			if fallbackAssignIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[fallbackAssignIdx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

